class Observable {
  constructor() {
    this.observers = [];
    // WeakMap for reverse lookup without creating strong circular reference
    this.observableRefs = new WeakMap();
  }

  subscribe(observer) {
    // Store observer reference
    this.observers.push(observer);

    // Use WeakMap instead of observer.observable = this
    // This allows observer to be GC'd when no longer referenced
    this.observableRefs.set(observer, this);

    // Return unsubscribe function
    return () => {
      const index = this.observers.indexOf(observer);
      if (index !== -1) {
        this.observers.splice(index, 1);
      }
      // Clean up WeakMap entry (optional, will be auto-collected)
      this.observableRefs.delete(observer);
    };
  }

  notify(event) {
    for (const observer of this.observers) {
      observer.update(event);
    }
  }

  // Helper method for observers to get observable reference if needed
  getObservableFor(observer) {
    return this.observableRefs.get(observer);
  }
}

module.exports = Observable;
EOF

