  constructor(id) { this.id = id; this.events = []; }
  update(event) { this.events.push(event); }
}

const observable = new Observable();
const unsubscribers = [];

// Create and subscribe 100 observers
for (let i = 0; i < 100; i++) {
  const observer = new TestObserver(i);
  const unsub = observable.subscribe(observer);
  unsubscribers.push(unsub);
  // Observer goes out of scope here
}

console.log('Created 100 observers');
console.log('Active observers:', observable.observers.length);

// Unsubscribe all
unsubscribers.forEach(unsub => unsub());

console.log('After unsubscribe all:', observable.observers.length);
console.log('All observers eligible for GC - no references retained');
EOF

